import React, {useState} from "react";
import GridOptions from "./modules/GridOptions.jsx";
import CssCanvas from "./CssCanvas.jsx";

// Currently there is no spot for ifGridSelected() to render. 
// When added as a function in the component it did not render.
// 

function CssMenu() {
    const [displayTypeState, setDisplayType] = useState("flex");
    let cssJson = {};
    let ifGridSelected = {display: "none"};

    function handleSubmit(e){
        e.preventDefault();
        const cssForm = e.target;
        const cssFormData = new FormData(cssForm);
        cssJson = Object.fromEntries(cssFormData.entries());
        console.log(cssJson);
        // ifGridSelected();
        console.log("cssJson.input1 === 'grid':", (cssJson.input1 === "grid"));
        if (cssJson.input1 === "grid"){
            ifGridSelected = {display: inherit};
        }
        else{
            ifGridSelected = {display: none};
        }


        setDisplayType(cssJson.input1);
    }

    return (
        <div className="CssPlayspace">
            <div className="CssMenu">
                <form onSubmit={handleSubmit}>
                    <label for="input1">display: </label>
                    <select name="input1" defaultValue={"flex"}>
                        <option value={"flex"}>flex</option>
                        <option value={"block"}>block</option>
                        <option value={"grid"}>grid</option>
                        <option value={"inline"}>inline</option>
                        <option value={"none"}>none</option>
                    </select>
                    <div style={ifGridSelected}>    
                        <GridOptions />
                    </div>    
                    <button type="submit">Refresh Canvas</button>
                </form>
            </div>
            <CssCanvas displayType={displayTypeState}/>
        </div>
    )
} 

export default CssMenu;
